import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Star, Leaf, HeartPulse, Sparkles, Truck } from 'lucide-react';
import { useCart } from '../context/CartContext';
import '../assets/styles/Product.css';

// Default detail block for mocking
const defaultDetails = {
  essenceQuote: '"A heirloom recipe passed down through generations, our Desi Gud is made by slowly reducing fresh sugarcane juice in shallow iron vats, retaining all natural minerals and its signature earthy caramel notes."',
  essenceDesc: 'Unlike refined sugar, our jaggery is unrefined and non-centrifuged. It is prepared using traditional methods without any sulfur or chemical clarificants. Each block is hand-poured, ensuring a texture that melts beautifully into your Masala Chai or morning porridge.',
  ingredients: ['Certified Sugarcane Juice', 'Wild Okra Stems (Natural Clarifier)'],
  nutrition: [
    { label: 'Energy', value: '383 kcal' },
    { label: 'Iron', value: '11.4 mg' },
    { label: 'Magnesium', value: '80 mg' }
  ],
  reviewsData: [
    { name: "Ananya R.", quote: "The depth of flavor is incomparable. It has this rich, smoky caramel undertone that you just don't get with store-bought jaggery.", stars: 5, initial: "A" },
    { name: "Siddharth M.", quote: "Used it for my child's teething biscuits. Knowing it's 100% chemical-free gives me so much peace of mind.", stars: 5, initial: "S" },
    { name: "Priya V.", quote: "The packaging is as beautiful as the product. Feels like receiving a luxury gift from nature itself.", stars: 5, initial: "P" }
  ],
  relatedData: [
    { title: "A2 Bilona Ghee", desc: "Churned from grass-fed Gir cows.", price: "₹1,250.00", image: "/images/a2-ghee-jar.png" },
    { title: "Wild Forest Honey", desc: "Raw, unpasteurized floral nectar.", price: "₹799.00", image: "/images/wild-honey.png" },
    { title: "Masala Chai Blend", desc: "Stone-ground spices and CTC tea.", price: "₹450.00", image: "/images/chai-blend.png" }
  ]
};

const productDatabase = {
  'desi-gud': {
    title: 'Desi Gud',
    tag: 'ARTISANAL CHOICE',
    description: 'Hand-crafted chemical-free jaggery blocks from the heart of sugarcane belts.',
    price: 349.00,
    originalPrice: 499.00,
    discount: '30% OFF',
    reviews: 128,
    images: ['/images/desi-gud-main.png', '/images/desi-gud-thumb1.png', '/images/desi-gud-thumb2.png'],
    benefits: [
      { id: 1, icon: <Leaf size={16} />, text: '100% Organic' },
      { id: 2, icon: <HeartPulse size={16} />, text: 'Iron Rich' },
      { id: 3, icon: <Sparkles size={16} />, text: 'No Chemicals' },
      { id: 4, icon: <Truck size={16} />, text: 'Direct Sourcing' },
    ],
    details: defaultDetails
  },
  'desi-ghee': {
    title: 'Sona Desi Ghee',
    tag: 'PURE A2 GHEE',
    description: 'Traditional bilona churned ghee from happy A2 cows. Rich in aroma and nutrients.',
    price: 1250.00,
    originalPrice: 1500.00,
    discount: '15% OFF',
    reviews: 350,
    images: ['/images/desi-ghee.png', '/images/desi-ghee.png', '/images/desi-ghee.png'],
    benefits: [
      { id: 1, icon: <Leaf size={16} />, text: 'A2 Milk' },
      { id: 2, icon: <HeartPulse size={16} />, text: 'Heart Healthy' },
      { id: 3, icon: <Sparkles size={16} />, text: 'Bilona Method' },
      { id: 4, icon: <Truck size={16} />, text: 'Farm Fresh' },
    ],
    details: {
      ...defaultDetails,
      essenceQuote: '"Slow-churned to perfection using earthen pots and a wooden bilona, capturing the golden essence of pure A2 milk."',
      ingredients: ['100% Pure A2 Cow Milk Fat'],
    }
  },
  'kaju-jaggery': {
    title: 'Kaju Jaggery',
    tag: 'PREMIUM BLEND',
    description: 'Rich, nutty jaggery infused with premium cashews for an elegant sweet treat.',
    price: 499.00,
    originalPrice: 650.00,
    discount: '23% OFF',
    reviews: 84,
    images: ['/images/kaju-jaggery.png', '/images/kaju-jaggery.png', '/images/kaju-jaggery.png'],
    benefits: [
      { id: 1, icon: <Leaf size={16} />, text: 'Premium Nuts' },
      { id: 2, icon: <HeartPulse size={16} />, text: 'Energy Boost' },
      { id: 3, icon: <Sparkles size={16} />, text: 'Handcrafted' },
      { id: 4, icon: <Truck size={16} />, text: 'Direct Sourcing' },
    ],
    details: defaultDetails
  },
  'jaggery-powder': {
    title: 'Jaggery Powder',
    tag: 'VERSATILE ESSENTIAL',
    description: 'Fine-textured pure jaggery powder, the perfect healthy alternative to refined sugar.',
    price: 250.00,
    originalPrice: 300.00,
    discount: '16% OFF',
    reviews: 210,
    images: ['/images/jaggery-powder.png', '/images/jaggery-powder.png', '/images/jaggery-powder.png'],
    benefits: [
      { id: 1, icon: <Leaf size={16} />, text: 'Easy to dissolve' },
      { id: 2, icon: <HeartPulse size={16} />, text: 'Nutrient Rich' },
      { id: 3, icon: <Sparkles size={16} />, text: 'No Chemicals' },
      { id: 4, icon: <Truck size={16} />, text: 'Direct Sourcing' },
    ],
    details: defaultDetails
  },
  'dry-fruit-jaggery': {
    title: 'Dry Fruit Jaggery',
    tag: 'CURATED LUXURY',
    description: 'A decadent blend of traditional jaggery generously studded with almonds and pistachios.',
    price: 450.00,
    originalPrice: 550.00,
    discount: '18% OFF',
    reviews: 95,
    images: ['/images/featured-1.png', '/images/featured-1.png', '/images/featured-1.png'],
    benefits: [
      { id: 1, icon: <Leaf size={16} />, text: '100% Organic' },
      { id: 2, icon: <HeartPulse size={16} />, text: 'Almonds & Pistas' },
      { id: 3, icon: <Sparkles size={16} />, text: 'No Chemicals' },
      { id: 4, icon: <Truck size={16} />, text: 'Direct Sourcing' },
    ],
    details: defaultDetails
  },
  'traditional-desi-ghee': {
    title: 'Traditional Desi Ghee',
    tag: 'HERITAGE GHEE',
    description: 'Classic artisanal ghee housed in a beautiful traditional clay pot.',
    price: 1250.00,
    originalPrice: 1500.00,
    discount: '15% OFF',
    reviews: 412,
    images: ['/images/featured-2.png', '/images/featured-2.png', '/images/featured-2.png'],
    benefits: [
      { id: 1, icon: <Leaf size={16} />, text: 'A2 Milk' },
      { id: 2, icon: <HeartPulse size={16} />, text: 'Bilona Churned' },
      { id: 3, icon: <Sparkles size={16} />, text: 'Clay Pot Aged' },
      { id: 4, icon: <Truck size={16} />, text: 'Direct Sourcing' },
    ],
    details: defaultDetails
  },
  'royal-desi-gud': {
    title: 'Royal Desi Gud',
    tag: 'CURATED LUXURY',
    description: 'Perfectly formed rectangular blocks of premium grade heritage jaggery.',
    price: 320.00,
    originalPrice: 400.00,
    discount: '20% OFF',
    reviews: 156,
    images: ['/images/featured-3.png', '/images/featured-3.png', '/images/featured-3.png'],
    benefits: [
      { id: 1, icon: <Leaf size={16} />, text: '100% Organic' },
      { id: 2, icon: <HeartPulse size={16} />, text: 'Iron Rich' },
      { id: 3, icon: <Sparkles size={16} />, text: 'Handcrafted' },
      { id: 4, icon: <Truck size={16} />, text: 'Direct Sourcing' },
    ],
    details: defaultDetails
  }
};

const Product = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { addToCart } = useCart();

  // Default to desi-gud if URL has unfamiliar ID
  const product = productDatabase[id] || productDatabase['desi-gud'];

  const [selectedWeight, setSelectedWeight] = useState('500g');
  const [activeImage, setActiveImage] = useState(product.images[0]);
  const [activeTab, setActiveTab] = useState('essence');

  // State for Review Form
  const [reviews, setReviews] = useState(product.details.reviewsData);
  const [showReviewForm, setShowReviewForm] = useState(false);
  const [newReview, setNewReview] = useState({ name: '', text: '', stars: 5 });

  // Re-sync image and reviews when navigating to a new product
  React.useEffect(() => {
    setActiveImage(product.images[0]);
    setActiveTab('essence'); 
    setReviews(product.details.reviewsData);
  }, [product]);

  return (
    <React.Fragment>
    <div className="product-page-container">
      <div className="product-grid">

        {/* Left Column: Image Gallery */}
        <div className="product-gallery">
          <div className="main-image-container">
            <div className="product-tag">{product.tag}</div>
            <img src={activeImage} alt={product.title} className="main-image" />
          </div>
          <div className="thumbnail-row">
            {product.images.slice(1).map((img, idx) => (
              <div 
                key={idx} 
                className={`thumbnail ${activeImage === img ? 'active' : ''}`}
                onClick={() => setActiveImage(img)}
              >
                <img src={img} alt={`${product.title} angle ${idx + 1}`} />
              </div>
            ))}
          </div>
        </div>

        {/* Right Column: Product Details */}
        <div className="product-details">

          <div className="reviews-row">
            <div className="stars">
              {[...Array(5)].map((_, i) => (
                <Star key={i} size={16} fill="#8B5E3C" color="#8B5E3C" className="star-icon" />
              ))}
            </div>
            <span className="review-count">({product.reviews} Reviews)</span>
          </div>

          <h1 className="product-title">{product.title}</h1>
          <p className="product-description">{product.description}</p>

          <div className="pricing-row">
            <span className="current-price">₹{product.price.toFixed(2)}</span>
            <span className="original-price">₹{product.originalPrice.toFixed(2)}</span>
            <span className="discount-tag">{product.discount}</span>
          </div>

          <div className="weight-selector">
            <p className="selector-label">SELECT WEIGHT</p>
            <div className="weight-options">
              <button 
                className={`weight-btn ${selectedWeight === '500g' ? 'active' : ''}`}
                onClick={() => setSelectedWeight('500g')}
              >
                500g
              </button>
              <button 
                className={`weight-btn ${selectedWeight === '1kg' ? 'active' : ''}`}
                onClick={() => setSelectedWeight('1kg')}
              >
                1kg
              </button>
            </div>
          </div>

          <div className="action-buttons">
            <button
              className="btn-add-to-cart"
              onClick={() => addToCart({
                productId: id,
                title: product.title,
                price: product.price,
                image: product.images[0],
                weight: selectedWeight,
                quantity: 1
              })}
            >ADD TO CART</button>
            <button
              className="btn-buy-now"
              onClick={async () => {
                await addToCart({
                  productId: id,
                  title: product.title,
                  price: product.price,
                  image: product.images[0],
                  weight: selectedWeight,
                  quantity: 1
                });
                navigate('/checkout');
              }}
            >BUY NOW</button>
          </div>

          <div className="benefits-grid">
            {product.benefits.map((benefit) => (
              <div key={benefit.id} className="benefit-item">
                <span className="benefit-icon">{benefit.icon}</span>
                <span className="benefit-text">{benefit.text}</span>
              </div>
            ))}
          </div>

        </div>

      </div>

      {/* Product Extended Info Section (Tabs) */}
      <div className="product-extended-info">
        <div className="info-tabs">
          <button 
            className={`tab-btn ${activeTab === 'essence' ? 'active' : ''}`}
            onClick={() => setActiveTab('essence')}
          >
            The Essence
          </button>
          <button 
            className={`tab-btn ${activeTab === 'ingredients' ? 'active' : ''}`}
            onClick={() => setActiveTab('ingredients')}
          >
            Ingredients
          </button>
          <button 
            className={`tab-btn ${activeTab === 'benefits' ? 'active' : ''}`}
            onClick={() => setActiveTab('benefits')}
          >
            Health Benefits
          </button>
        </div>

        <div className="tab-divider"></div>

        {activeTab === 'essence' && (
          <div className="tab-content essence-content fade-in">
            <p className="essence-quote">{product.details.essenceQuote}</p>
            <p className="essence-desc">{product.details.essenceDesc}</p>

            <div className="essence-split">
              <div className="split-column">
                <h3 className="split-heading">Pure Ingredients</h3>
                <ul className="ingredient-list">
                  {product.details.ingredients.map((item, i) => (
                    <li key={i}>{item}</li>
                  ))}
                </ul>
              </div>
              <div className="split-column">
                <h3 className="split-heading">Nutrition Facts</h3>
                <div className="nutrition-table">
                  {product.details.nutrition.map((item, i) => (
                    <div className="nutrition-row" key={i}>
                      <span className="nutrition-label">{item.label}</span>
                      <span className="nutrition-value">{item.value}</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'ingredients' && (
          <div className="tab-content fade-in">
            <p className="essence-desc">Detailed ingredient information will go here.</p>
          </div>
        )}

        {activeTab === 'benefits' && (
          <div className="tab-content fade-in">
            <p className="essence-desc">Extensive health benefits breakdown will go here.</p>
          </div>
        )}
      </div>

      {/* Voices of Purity Section */}
      <div className="reviews-section">
        <div className="reviews-header">
          <div className="reviews-title-block">
            <h2>Voices of Purity</h2>
            <p>What our atelier community has to say.</p>
          </div>
          <button className="btn-write-review" onClick={() => setShowReviewForm(true)}>WRITE A REVIEW</button>
        </div>

        <div className="reviews-grid">
          {reviews.map((review, idx) => (
            <div className="review-card" key={idx}>
              <div className="review-stars">
                {[...Array(review.stars)].map((_, i) => (
                  <Star key={i} size={14} fill="#6a462b" color="#6a462b" />
                ))}
              </div>
              <p className="review-quote">"{review.quote}"</p>
              <div className="review-author">
                <div className="author-avatar">{review.initial}</div>
                <div className="author-info">
                  <span className="author-name">{review.name}</span>
                  <span className="author-verified">Verified Collector</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>

    {/* Pairs Beautifully Width Section (Full width colored wrapper) */}
    <div className="related-section-wrapper">
      <div className="related-container">
        <h2 className="related-title">Pairs beautifully with...</h2>

        <div className="related-grid">
          {product.details.relatedData.map((item, idx) => (
            <div className="related-card" key={idx}>
              <img src={item.image} alt={item.title} className="related-image" />
              <div className="related-info">
                <div>
                  <h3 className="related-itemName">{item.title}</h3>
                  <p className="related-desc">{item.desc}</p>
                </div>
                <div className="related-price-row">
                  <span className="related-price">{item.price}</span>
                  <button className="btn-plus" aria-label="Quick Add">+</button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>

    {/* Form Modal Overlay */}
    {showReviewForm && (
      <div className="review-modal-overlay">
        <div className="review-modal-content fade-in">
           <div className="modal-header">
             <h3>Write a Review</h3>
             <button className="close-modal" onClick={() => setShowReviewForm(false)}>✕</button>
           </div>

           <form onSubmit={(e) => {
              e.preventDefault();
              if(!newReview.name || !newReview.text) return;
              const reviewObj = {
                name: newReview.name,
                quote: newReview.text,
                stars: newReview.stars,
                initial: newReview.name.charAt(0).toUpperCase()
              };
              setReviews([reviewObj, ...reviews]);
              setShowReviewForm(false);
              setNewReview({ name: '', text: '', stars: 5 });
           }} className="review-form">
              <label>Your Name</label>
              <input type="text" placeholder="Enter your name" value={newReview.name} onChange={(e) => setNewReview({...newReview, name: e.target.value})} required />

              <label>Rating</label>
              <div className="star-rating-select">
                 {[1,2,3,4,5].map(num => (
                    <Star 
                      key={num} 
                      size={28} 
                      fill={num <= newReview.stars ? '#8B5E3C' : 'transparent'} 
                      color="#8B5E3C" 
                      onClick={() => setNewReview({...newReview, stars: num})}
                      className="clickable-star"
                    />
                 ))}
              </div>

              <label>Your Review</label>
              <textarea placeholder="Share your experience with this product..." rows="5" value={newReview.text} onChange={(e) => setNewReview({...newReview, text: e.target.value})} required></textarea>

              <button type="submit" className="btn-submit-review">Submit Review</button>
           </form>
        </div>
      </div>
    )}

    </React.Fragment>
  );
};

export default React.memo(Product);
